import{_ as s,C as n,o as l,c as d,j as t,a as i,E as a,ag as o}from"./chunks/framework.DLWhSH9p.js";const y=JSON.parse('{"title":"Marketplace","description":"","frontmatter":{},"headers":[],"relativePath":"guide/marketplace.md","filePath":"guide/marketplace.md"}'),c={name:"guide/marketplace.md"};function g(p,e,h,m,u,b){const r=n("FlatImage");return l(),d("div",null,[e[0]||(e[0]=t("h1",{id:"marketplace",tabindex:"-1"},[i("Marketplace "),t("a",{class:"header-anchor",href:"#marketplace","aria-label":'Permalink to "Marketplace"'},"​")],-1)),e[1]||(e[1]=t("p",null,"The Marketplace is where you hire voice actors, musicians, on-camera spokespersons, editors, and animators for your channel — and, if you're a creator, where you list yourself for hire.",-1)),e[2]||(e[2]=t("p",null,[i("It lives at "),t("strong",null,[t("a",{href:"https://marketplace.mossworks.io/",target:"_blank",rel:"noreferrer"},"marketplace.mossworks.io")]),i(" and is reachable from CRAFT via the "),t("code",null,"craft ↗"),i(" link in the top-right of the marketplace (and vice versa).")],-1)),a(r,{name:"marketplace-browse",alt:"Marketplace browse"}),e[3]||(e[3]=o('<h2 id="the-pricing-model" tabindex="-1">The pricing model <a class="header-anchor" href="#the-pricing-model" aria-label="Permalink to &quot;The pricing model&quot;">​</a></h2><p>The Marketplace&#39;s defining commitment: <strong>sellers pay $0 in platform fees</strong>. Buyers pay a flat <strong>15% marketplace fee</strong> on top of the seller&#39;s quoted price, and that&#39;s it — no card fees layered in, no hidden cuts on the seller side.</p><p>Storage is the only line item creators ever see. It scales with the library they upload — enough to prevent abuse, not enough to matter in practice ($4/mo for 25 GB at the current tier). Listings, demos, messaging, contracts, payouts, and 1099 issuance are all free.</p><h2 id="sub-views" tabindex="-1">Sub-views <a class="header-anchor" href="#sub-views" aria-label="Permalink to &quot;Sub-views&quot;">​</a></h2><p>The Marketplace&#39;s top nav has exactly four tabs: <strong>Browse · Gigs · Brand partners · My Studio</strong>.</p><h3 id="browse" tabindex="-1">Browse <a class="header-anchor" href="#browse" aria-label="Permalink to &quot;Browse&quot;">​</a></h3><p>Filter rail on the left (category, style/vibe, language, turnaround, price), hero stats, a <strong>Spotlight rail</strong> of top creators (≥ 4.8★ with ≥ 25 completed jobs in any role), then a grid of everyone else. Each card shows role, rating, jobs completed, rate, and — for voice actors — a mini-waveform demo or filmstrip preview.</p><p><strong>Categories</strong></p><ul><li><strong>Voice actors</strong> — narration, spokesperson, ad reads</li><li><strong>Spokespersons</strong> — on-camera hosts</li><li><strong>Musicians</strong> — custom tracks, ambient, orchestral, electronic</li><li><strong>Editors</strong> — pacing surgery, shorts-first cuts, long-form docs</li><li><strong>Animators</strong> — 2D motion, 3D, explainer, data-viz</li></ul><h3 id="gigs" tabindex="-1">Gigs <a class="header-anchor" href="#gigs" aria-label="Permalink to &quot;Gigs&quot;">​</a></h3>',10)),a(r,{name:"marketplace-gigs",alt:"Open gigs — filter rail + gig cards"}),e[4]||(e[4]=o('<p>Gigs is the flip side of Browse — instead of buyers searching for creators, creators see <strong>channels posting what they need</strong> and apply with a message + quote.</p><p><strong>For creators</strong></p><ol><li>Open <strong>Gigs</strong> in the marketplace top nav.</li><li>Filter by role, budget, deadline, status.</li><li>Click a gig card to see the full brief (description, deliverables, tags, budget).</li><li>Submit an application — short pitch + your quote.</li></ol><p>The buyer sees your application under their gig. If they shortlist or accept you, the next step is the standard <a href="#hire-contract">Hire &amp; contract</a> flow against your quote.</p><p><strong>For buyers — Post a gig</strong></p>',5)),a(r,{name:"marketplace-post-gig",alt:"Post a gig form with live preview"}),e[5]||(e[5]=o('<p>Click <strong>+ Post a gig</strong> in the top-right of the marketplace top bar. The form has:</p><ul><li><strong>Title</strong> — the headline creators see in the list</li><li><strong>Role</strong> — voice / spokesperson / music / editor / animator</li><li><strong>Description</strong> — the brief (context, tone, samples, deadlines)</li><li><strong>Deliverables</strong> — file formats, revisions, timeline</li><li><strong>Budget min / max</strong> — displayed as a range on the card</li><li><strong>Deadline</strong> — free-text (e.g. &quot;Apr 28&quot; or &quot;Ongoing&quot;)</li><li><strong>Tags</strong> — comma-separated search keywords</li><li><strong>Your name / channel</strong> — attribution shown on the gig</li></ul><p>A live preview card sits to the right so you can see the cards as applicants will. Nothing is charged at post-time — funds only move through escrow once you <strong>accept</strong> a specific applicant.</p><h3 id="brand-partners" tabindex="-1">Brand partners <a class="header-anchor" href="#brand-partners" aria-label="Permalink to &quot;Brand partners&quot;">​</a></h3><div class="info custom-block"><p class="custom-block-title">Coming soon</p><p>Brand-partner listings, two-sided reviews, and placement matching aren&#39;t live yet. The tab today shows a coming-soon slide with placeholder partner cards so you can preview the layout.</p></div>',5)),a(r,{name:"marketplace-brand-partners",alt:"Brand partners — coming soon with sample partner cards"}),e[6]||(e[6]=o('<p>Brand partners is the <strong>brand-sponsorship</strong> side of the Marketplace — distinct from creators-for-hire. Two populations live here:</p><ul><li><strong>Channels seeking sponsors</strong> — audience, niche, sample reads, CPM ranges</li><li><strong>Brands seeking channels</strong> — products, campaigns, deliverable expectations, budgets</li></ul><p>Both render as partner cards with hue-themed covers, tier badges (see <a href="#gamification-tiers-badges-streaks">Gamification</a>), active listings count, and a spotlight flag for top performers. Reviews are <strong>placement-scoped</strong>, not gig-scoped — they reference a specific placement so both sides can back-reference the engagement. Same star-rating mechanics as creator reviews, same merit-only ranking — no paid boosts.</p><h3 id="artist-profile" tabindex="-1">Artist profile <a class="header-anchor" href="#artist-profile" aria-label="Permalink to &quot;Artist profile&quot;">​</a></h3>',4)),a(r,{name:"marketplace-artist-profile",alt:"Artist public profile — bio, languages, packages, ratings, hire sidebar"}),e[7]||(e[7]=o('<p>Cover image, demo reel with inline audio playback, reviews, and a sticky hire sidebar. The sidebar has:</p><ul><li>Headline rate</li><li>Minimum order &amp; typical reply time</li><li>Package tiers (e.g. &quot;Script under 500w · 24h · $60&quot;, &quot;Documentary narration · 3 days · $210&quot;)</li><li><strong>Request this creator →</strong> (starts the hire flow)</li><li><strong>Send a message first</strong> (real messaging — not mocked)</li></ul><h3 id="my-studio" tabindex="-1">My Studio <a class="header-anchor" href="#my-studio" aria-label="Permalink to &quot;My Studio&quot;">​</a></h3>',3)),a(r,{name:"marketplace-studio",alt:"My Studio — seller dashboard with tier, badges, contribution weights"}),e[8]||(e[8]=o('<p>If you&#39;re a creator, this is your home. The page is built in three layers:</p><p><strong>Hero row</strong> — a progression tile on the left (your tier badge, tier-score progress bar, top earned badges, active streak, recent achievements, onboarding completeness) + a spotlight card on the right (this-quarter job progress against the goal, per-role eligibility breakdown, contribution weights — rating 40% / on-time 30% / volume 20% / reply 10%).</p><p><strong>Five-stat grid</strong> — 90-day rating, active gigs, completed gigs, this-quarter progress, setup completion (X/21).</p><p><strong>Three internal tabs</strong></p><ul><li><strong>Metrics</strong> (default) — earned + locked badges with show/hide toggle, and your most recent reviews.</li><li><strong>Active gigs</strong> — table of in-progress contracts with status, deadline, amount. Click a row for the full contract view.</li><li><strong>Partnerships</strong> — placeholder for &quot;Brands I worked with&quot; with a &quot;Leave review&quot; button per partner — turns on when brand partners launches.</li></ul><p><strong>Quick links rail</strong> at the bottom — Profile · Demos · Packages · Availability · Stripe · Storage · Invitations · Applications · Contracts · Disputes. One-click jumps to every per-role surface without crowding the top nav.</p><h2 id="gamification-tiers-badges-streaks" tabindex="-1">Gamification: tiers, badges, streaks <a class="header-anchor" href="#gamification-tiers-badges-streaks" aria-label="Permalink to &quot;Gamification: tiers, badges, streaks&quot;">​</a></h2><p>Creators and brand partners earn <strong>visible, criterion-based recognition</strong> based on their public stats. Nothing here is pay-to-play — tiers and badges are computed from your rating, completed-job count, on-time percentage, and reply speed. The rationale for every badge is visible in the UI, so there&#39;s no mystery about what unlocked it.</p><h3 id="tiers" tabindex="-1">Tiers <a class="header-anchor" href="#tiers" aria-label="Permalink to &quot;Tiers&quot;">​</a></h3><p>Four tiers, gated on hard thresholds — all three criteria must be met to advance:</p><table tabindex="0"><thead><tr><th>Tier</th><th style="text-align:right;">Rating</th><th style="text-align:right;">Completed jobs</th><th style="text-align:right;">On-time</th></tr></thead><tbody><tr><td><strong>Bronze</strong></td><td style="text-align:right;">—</td><td style="text-align:right;">—</td><td style="text-align:right;">—</td></tr><tr><td><strong>Silver</strong></td><td style="text-align:right;">≥ 4.5</td><td style="text-align:right;">≥ 10</td><td style="text-align:right;">≥ 90%</td></tr><tr><td><strong>Gold</strong></td><td style="text-align:right;">≥ 4.8</td><td style="text-align:right;">≥ 50</td><td style="text-align:right;">≥ 95%</td></tr><tr><td><strong>Platinum</strong></td><td style="text-align:right;">≥ 4.9</td><td style="text-align:right;">≥ 150</td><td style="text-align:right;">≥ 98%</td></tr></tbody></table><p>The profile card also shows a tier score (0–100): <strong>40% rating · 30% volume · 20% on-time · 10% reply speed</strong>. It&#39;s a smooth signal between tier jumps so progress is legible.</p><h3 id="badges" tabindex="-1">Badges <a class="header-anchor" href="#badges" aria-label="Permalink to &quot;Badges&quot;">​</a></h3><p>Badges are <strong>current-state</strong> flags — they turn on and off as stats move. Examples: <code>Spotlight eligible</code> (≥ 4.8★ + ≥ 25 jobs), <code>Fast replier</code> (avg reply ≤ 3h), <code>Multilingual</code> (two or more delivery languages), <code>Veteran</code> (100+ completed jobs). Each badge lists its rationale on hover so there&#39;s no guesswork.</p><h3 id="achievements" tabindex="-1">Achievements <a class="header-anchor" href="#achievements" aria-label="Permalink to &quot;Achievements&quot;">​</a></h3><p>Achievements are <strong>permanent</strong> milestones — once unlocked, they stay. Rarity tiers: <code>common</code> · <code>uncommon</code> · <code>rare</code> · <code>legendary</code>. Examples: <code>First gig delivered</code>, <code>First repeat client</code>, <code>Five-gig streak</code>, <code>Spotlighted 3 weeks</code>, <code>100 gigs completed</code>. Unlocks show the date in the profile&#39;s achievements strip.</p><h3 id="streaks" tabindex="-1">Streaks <a class="header-anchor" href="#streaks" aria-label="Permalink to &quot;Streaks&quot;">​</a></h3><p>Streaks are <strong>consecutive counters</strong> that reset when broken but remain visible as historical markers. Examples: <code>On-time streak · 47 days</code>, <code>Five-star streak · 6 deliveries</code>, <code>Reply-time streak · 21 days</code>. An inactive streak renders muted to show the last peak.</p><h3 id="next-tier-hint" tabindex="-1">Next-tier hint <a class="header-anchor" href="#next-tier-hint" aria-label="Permalink to &quot;Next-tier hint&quot;">​</a></h3><p>Every profile shows what&#39;s still needed for the next tier — e.g. <code>Gold → Platinum: rating ≥ 4.9, +50 completed jobs, on-time ≥ 98%</code>. No gamified carrot; just a concrete list so creators know exactly what moves the needle.</p><h2 id="seller-onboarding" tabindex="-1">Seller onboarding <a class="header-anchor" href="#seller-onboarding" aria-label="Permalink to &quot;Seller onboarding&quot;">​</a></h2><p>Becoming a seller is a 21-item checklist split across three sections — <strong>Identity</strong>, <strong>Profile</strong>, and <strong>Stripe</strong>. The wizard tracks every item; your seller listing turns on automatically when the full checklist passes, and three Stripe-side items (age, legal name, tax form) short-circuit once Stripe completes verification.</p>',22)),a(r,{name:"marketplace-onboarding-start",alt:"Onboarding checklist — 4 of 21 items, identity / profile / stripe sections"}),e[9]||(e[9]=t("p",null,`The left rail shows progress and lets you jump to any item; the main pane walks one step at a time with a single "Open …" CTA so there's no ambiguity about what's next. Strikethrough indicates completed items.`,-1)),e[10]||(e[10]=t("h3",{id:"stripe-handoff",tabindex:"-1"},[i("Stripe handoff "),t("a",{class:"header-anchor",href:"#stripe-handoff","aria-label":'Permalink to "Stripe handoff"'},"​")],-1)),e[11]||(e[11]=t("p",null,"Government-ID verification, tax forms (W-8BEN / W-9), bank-account verification, and 1099 issuance all live in Stripe — we never see any of it, only the verification status.",-1)),a(r,{name:"marketplace-stripe-handoff",alt:"Stripe handoff — four checks waiting on Stripe"}),e[12]||(e[12]=o('<p>The four checks — Stripe account created, details submitted, charges enabled, payouts enabled — flip green as Stripe completes each step. The <strong>Resolve in Stripe</strong> button opens Stripe&#39;s hosted onboarding flow in a new tab; typical completion time is around 8 minutes for a first-time seller.</p><h2 id="hire-contract" tabindex="-1">Hire &amp; contract <a class="header-anchor" href="#hire-contract" aria-label="Permalink to &quot;Hire &amp; contract&quot;">​</a></h2><p>A 4-step stepper: <strong>Brief → Scope &amp; schedule → Contract → Pay &amp; start</strong>. The contract is CRAFT-standard with fields for parties, deliverable, format, revisions, delivery date, usage rights, and credit line. The payment summary breaks out:</p><ul><li><code>{words} × {rate}</code> → creator receives</li><li><code>Marketplace fee (15%)</code></li><li><strong>You pay</strong> total</li></ul><p>Funds are held in escrow until you accept the deliverable. Single-payment contracts hold one charge for the whole agreed price; milestone contracts hold each milestone independently and release them as you accept each one. Refunds, cancels, and dispute handling are all available from the contract view.</p>',5))])}const k=s(c,[["render",g]]);export{y as __pageData,k as default};
